fn calculate_total_file_size(file_sizes: Vec<u64>) -> u64 {
    file_sizes.iter().sum()
}

fn calculate_total_file_size_wrapping(file_sizes: Vec<u64>) -> u64 {
    file_sizes.iter().fold(0u64, |acc, &size| acc.wrapping_add(size))
}

fn calculate_total_file_size_checked(file_sizes: Vec<u64>) -> Option<u64> {
    file_sizes.iter().try_fold(0u64, |acc, &size| acc.checked_add(size))
}

fn has_sufficient_disk_space(file_sizes: Vec<u64>, available_space: u64) -> bool {
    let total_size = calculate_total_file_size(file_sizes);
    total_size <= available_space
}

fn calculate_batch_sizes(file_sizes: Vec<u64>, batch_limit: u64) -> Vec<Vec<u64>> {
    let mut batches = Vec::new();
    let mut current_batch = Vec::new();
    let mut current_size = 0u64;
    
    for size in file_sizes {
        if current_size + size > batch_limit && !current_batch.is_empty() {
            batches.push(current_batch);
            current_batch = Vec::new();
            current_size = 0;
        }
        current_batch.push(size);
        current_size += size;
    }
    
    if !current_batch.is_empty() {
        batches.push(current_batch);
    }
    
    batches
}